@dataclass(frozen=True)
class ClipRenderData:
    """Command generated by Clay when the type is SCISSOR_START or SCISSOR_END."""

    horizontal: bool
    vertical: bool

    @classmethod
    def from_ctypes(cls, c: ct.Clay_ClipRenderData) -> ClipRenderData:
        """Convert the underlying ctypes structure to the Python dataclass."""
        return cls(horizontal=c.horizontal, vertical=c.vertical)


@dataclass(frozen=True)
class OverlayColorRenderData:
    """Command generated by Clay when the type is OVERLAY_START or OVERLAY_END."""

    color: Color

    @classmethod
    def from_ctypes(cls, c: ct.Clay_OverlayColorRenderData) -> OverlayColorRenderData:
        """Convert the underlying ctypes structure to the Python dataclass."""
