@dataclass(frozen=True)
class BorderRenderData:
    """Command generated by Clay when the type is BORDER."""

    color: Color
    corner_radius: CornerRadius
    width: BorderWidth

    @classmethod
    def from_ctypes(cls, c: ct.Clay_BorderRenderData) -> BorderRenderData:
        """Convert the underlying ctypes structure to the Python dataclass."""
        return cls(
            color=Color.from_ctypes(c.color),
            corner_radius=CornerRadius.from_ctypes(c.cornerRadius),
            width=BorderWidth.from_ctypes(c.width),
        )


@dataclass(frozen=True)
class RenderCommand:
    """Represents a single render command generated by Clay."""

    bounding_box: BoundingBox
    command_type: Clay_RenderCommandType

    # optional data depending on the type
    rectangle: RectangleRenderData | None = None
    text: TextRenderData | None = None
    image: ImageRenderData | None = None
    custom: CustomRenderData | None = None
    border: BorderRenderData | None = None
    clip: ClipRenderData | None = None
    overlay_color: OverlayColorRenderData | None = None

    user_data: Any = None
    id: int = 0
    z_index: int = 0

    @classmethod
    def from_ctypes(cls, c: ct.Clay_RenderCommand) -> RenderCommand:
        """Convert the underlying ctypes structure to the Python dataclass."""
        cmd_type: Clay_RenderCommandType = Clay_RenderCommandType(c.commandType)
        cmd_types = Clay_RenderCommandType

        rectangle = text = image = custom = border = clip = overlay_color = None
        match cmd_type:
            case cmd_types.CLAY_RENDER_COMMAND_TYPE_RECTANGLE:
                rectangle = RectangleRenderData.from_ctypes(c.renderData.rectangle)
            case cmd_types.CLAY_RENDER_COMMAND_TYPE_TEXT:
                text = TextRenderData.from_ctypes(c.renderData.text)
            case cmd_types.CLAY_RENDER_COMMAND_TYPE_IMAGE:
                image = ImageRenderData.from_ctypes(c.renderData.image)
            case cmd_types.CLAY_RENDER_COMMAND_TYPE_CUSTOM:
                custom = CustomRenderData.from_ctypes(c.renderData.custom)
            case cmd_types.CLAY_RENDER_COMMAND_TYPE_BORDER:
                border = BorderRenderData.from_ctypes(c.renderData.border)
            case (
                cmd_types.CLAY_RENDER_COMMAND_TYPE_SCISSOR_START
                | cmd_types.CLAY_RENDER_COMMAND_TYPE_SCISSOR_END
            ):
                clip = ClipRenderData.from_ctypes(c.renderData.clip)
            case (
                cmd_types.CLAY_RENDER_COMMAND_TYPE_OVERLAY_COLOR_START
                | cmd_types.CLAY_RENDER_COMMAND_TYPE_OVERLAY_COLOR_END
            ):
                overlay_color = OverlayColorRenderData.from_ctypes(
                    c.renderData.overlayColor,
                )
        # TODO(oxygen): load user data
        user_data = None

        return cls(
            bounding_box=BoundingBox.from_ctypes(c.boundingBox),
            command_type=cmd_type,
            rectangle=rectangle,
            text=text,
            image=image,
            custom=custom,
            border=border,
            clip=clip,
            overlay_color=overlay_color,
            user_data=user_data,
            id=c.id,
            z_index=c.zIndex,
        )
